-- Set is_latest for the most recent report in each version chain
UPDATE reports SET is_latest = true WHERE id IN (  SELECT DISTINCT ON (version_chain_id) id FROM reports   WHERE device_id LIKE 'device-seed-%'   ORDER BY version_chain_id, submitted_at DESC);
